target.script:

var langstring = project.getProperty("langs");
var igTemp = project.getProperty("ig.temp");
var langs = langstring.split(";");
for (var i = 0; i < langs.length; i++) {
  if (langs[i] !== "") {
    var dir = new java.io.File(igTemp + "/_includes/" + langs[i]);
    dir.mkdirs();
  }
}
